/**
 * Creates a debounced version of the supplied function.
 *
 * The debounced function postpones its execution until after `delay` milliseconds
 * have elapsed since the last time it was invoked.
 *
 * @param {Function} fn    The function to debounce.
 * @param {number}   delay The debounce delay in milliseconds.
 * @param {Object}   [options] Optional configuration:
 *   - {boolean} leading  If true, invoke on the leading edge of the timeout.
 *   - {boolean} trailing If false, suppress the trailing‑edge call.
 *   - {Function} [maxWait] If provided, ensures the function is invoked at least
 *                          once every `maxWait` milliseconds.
 *
 * @returns {Function} A new debounced function with a `cancel` and `flush` method.
 */
function debounce(fn, delay, options = {}) {
  let timerId = null;          // ID of the pending timeout
  let lastArgs = null;         // Arguments of the most recent call
  let lastThis = null;         // `this` of the most recent call
  let lastCallTime = 0;        // Timestamp of the last call
  let maxWaitTimerId = null;   // ID for the optional max‑wait timer

  const { leading = false, trailing = true, maxWait } = options;

  // Helper: invoke the original function with the stored context/args
  const invoke = () => {
    const result = fn.apply(lastThis, lastArgs);
    // Reset state after invoking
    lastArgs = lastThis = null;
    return result;
  };

  // Clears both the regular and max‑wait timers
  const clearTimers = () => {
    if (timerId !== null) {
      clearTimeout(timerId);
      timerId = null;
    }
    if (maxWaitTimerId !== null) {
      clearTimeout(maxWaitTimerId);
      maxWaitTimerId = null;
    }
  };

  // The debounced wrapper
  const debounced = function (...args) {
    const now = Date.now();
    const isInvokingLeading = leading && timerId === null;

    // Save the latest context and arguments
    lastArgs = args;
    lastThis = this;
    lastCallTime = now;

    // If leading edge should fire immediately
    if (isInvokingLeading) {
      invoke();
    }

    // Clear any existing trailing timer
    if (timerId !== null) {
      clearTimeout(timerId);
    }

    // Set up trailing call if required
    if (trailing) {
      timerId = setTimeout(() => {
        timerId = null;
        // If leading was also true, we only want to call on trailing
        // when there have been new calls after the leading invocation.
        if (!leading || lastArgs) {
          invoke();
        }
      }, delay);
    }

    // Handle maxWait logic, if provided
    if (typeof maxWait === 'number') {
      if (maxWaitTimerId === null) {
        // First call – start the max‑wait timer
        maxWaitTimerId = setTimeout(() => {
          maxWaitTimerId = null;
          if (lastArgs) {
            // Force an invoke even if the normal debounce timer hasn't fired yet
            clearTimeout(timerId);
            timerId = null;
            invoke();
          }
        }, maxWait);
      }
    }

    // Return whatever the original function returns on leading edge,
    // otherwise undefined (standard debounce pattern)
    return isInvokingLeading ? fn.apply(lastThis, args) : undefined;
  };

  // Cancel any pending invocation
  debounced.cancel = () => {
    clearTimers();
    lastArgs = lastThis = null;
  };

  // Immediately invoke any pending trailing call
  debounced.flush = () => {
    if (timerId !== null) {
      clearTimeout(timerId);
      timerId = null;
      if (lastArgs) {
        invoke();
      }
    }
    // Also clear the max‑wait timer, if any
    if (maxWaitTimerId !== null) {
      clearTimeout(maxWaitTimerId);
      maxWaitTimerId = null;
    }
  };

  return debounced;
}

/* -------------------------------------------------
   Example usage
------------------------------------------------- */
// Function we want to debounce
function onResize(event) {
  console.log('Resized at', new Date().toISOString());
}

// Debounced version: fires 300 ms after the last resize event
const debouncedResize = debounce(onResize, 300);

// Attach to a DOM event
window.addEventListener('resize', debouncedResize);

// You can also control it manually:
debouncedResize.cancel(); // stops any pending call
debouncedResize.flush();  // forces immediate execution if waiting
```

function debounce(fn, delay) {
  let timer;
  return function (...args) {
    clearTimeout(timer);
    timer = setTimeout(() => fn.apply(this, args), delay);
  };
}

```javascript
function debounce(func, delay) {
  let timeoutId;

  return function(...args) {
    // Clear the previous timer to reset the delay
    clearTimeout(timeoutId);

    // Set a new timer to execute the function after the delay
    timeoutId = setTimeout(() => {
      func.apply(this, args);
    }, delay);
  };
}
```
